71	export interface MultipartPart {
72	  headers: Record<string, string>;
73	  body: Uint8Array;
74	}
75	
76	export function parseMultipart(
77	  data: Uint8Array,
78	  boundary: string,
79	): MultipartPart[] {
80	  const parts: MultipartPart[] = [];
81	  const boundaryBytes = new TextEncoder().encode(`--${boundary}`);
82	  const endBoundaryBytes = new TextEncoder().encode(`--${boundary}--`);
83	
84	  const positions: number[] = [];
85	  for (let i = 0; i <= data.length - boundaryBytes.length; i++) {
86	    let match = true;
87	    for (let j = 0; j < boundaryBytes.length; j++) {
88	      if (data[i + j] !== boundaryBytes[j]) {
89	        match = false;
90	        break;
91	      }
92	    }
93	    if (match) {
94	      positions.push(i);
95	    }
96	  }
97	
98	  for (let i = 0; i < positions.length - 1; i++) {
99	    const start = positions[i] + boundaryBytes.length;
100	    const end = positions[i + 1];
101	
102	    let isEndBoundary = true;
103	    for (let j = 0; j < endBoundaryBytes.length && isEndBoundary; j++) {
104	      if (data[positions[i] + j] !== endBoundaryBytes[j]) {
105	        isEndBoundary = false;
106	      }
107	    }
108	    if (
109	      isEndBoundary &&
110	      positions[i] + endBoundaryBytes.length <= data.length
111	    ) {
112	      continue;
113	    }
114	
115	    let partStart = start;
116	    if (data[partStart] === 0x0d && data[partStart + 1] === 0x0a) {
117	      partStart += 2;
118	    } else if (data[partStart] === 0x0a) {
119	      partStart += 1;
120	    }
121	
122	    let partEnd = end;
123	    if (data[partEnd - 2] === 0x0d && data[partEnd - 1] === 0x0a) {
124	      partEnd -= 2;
125	    } else if (data[partEnd - 1] === 0x0a) {
126	      partEnd -= 1;
127	    }
128	
129	    const partData = data.slice(partStart, partEnd);
130	
131	    let headerEnd = -1;
132	    for (let j = 0; j < partData.length - 3; j++) {
133	      if (
134	        partData[j] === 0x0d &&
135	        partData[j + 1] === 0x0a &&
136	        partData[j + 2] === 0x0d &&
137	        partData[j + 3] === 0x0a
138	      ) {
139	        headerEnd = j;
140	        break;
141	      }
142	      if (partData[j] === 0x0a && partData[j + 1] === 0x0a) {
143	        headerEnd = j;
144	        break;
145	      }
146	    }
147	
148	    if (headerEnd === -1) {
149	      continue;
150	    }
151	
152	    const headerBytes = partData.slice(0, headerEnd);
153	    const headerStr = new TextDecoder().decode(headerBytes);
154	    const headers: Record<string, string> = {};
155	    for (const line of headerStr.split(/\r?\n/)) {
156	      const colonIdx = line.indexOf(':');
157	      if (colonIdx > 0) {
158	        const key = line.slice(0, colonIdx).trim().toLowerCase();
159	        const value = line.slice(colonIdx + 1).trim();
160	        headers[key] = value;
161	      }
162	    }
163	
164	    let bodyStart = headerEnd + 2;
165	    if (partData[headerEnd] === 0x0d) {
166	      bodyStart = headerEnd + 4;
167	    }
168	    const body = partData.slice(bodyStart);
169	
170	    parts.push({ headers, body });
171	  }
172	
173	  return parts;
174	}
