5	function createMultipartResponse(
6	  jobResult: Record<string, unknown>,
7	  imageContent: string = 'test-image',
8	): { body: Buffer; contentType: string } {
9	  const boundary = 'test-boundary-12345';
10	  const jobJson = JSON.stringify(jobResult);
11	  const imageBuffer = Buffer.from(imageContent);
12	
13	  const parts = [
14	    `--${boundary}\r\n`,
15	    'Content-Disposition: form-data; name="job"; filename="job.json"\r\n',
16	    'Content-Type: application/json\r\n',
17	    '\r\n',
18	    jobJson,
19	    '\r\n',
20	    `--${boundary}\r\n`,
21	    'Content-Disposition: form-data; name="output"; filename="output.png"\r\n',
22	    'Content-Type: image/png\r\n',
23	    '\r\n',
24	  ];
25	
26	  const headerPart = Buffer.from(parts.join(''));
27	  const endPart = Buffer.from(`\r\n--${boundary}--\r\n`);
28	
29	  const body = Buffer.concat([headerPart, imageBuffer, endPart]);
30	
31	  return {
32	    body,
33	    contentType: `multipart/form-data; boundary=${boundary}`,
34	  };
35	}
