1	import { InvalidArgumentError } from '@ai-sdk/provider';
2	import { safeValidateTypes } from './validate-types';
3	import { FlexibleSchema } from './schema';
4	
5	export async function parseProviderOptions<OPTIONS>({
6	  provider,
7	  providerOptions,
8	  schema,
9	}: {
10	  provider: string;
11	  providerOptions: Record<string, unknown> | undefined;
12	  schema: FlexibleSchema<OPTIONS>;
13	}): Promise<OPTIONS | undefined> {
14	  if (providerOptions?.[provider] == null) {
15	    return undefined;
16	  }
17	
18	  const parsedProviderOptions = await safeValidateTypes<OPTIONS | undefined>({
19	    value: providerOptions[provider],
20	    schema,
21	  });
22	
23	  if (!parsedProviderOptions.success) {
24	    throw new InvalidArgumentError({
25	      argument: 'providerOptions',
26	      message: `invalid ${provider} provider options`,
27	      cause: parsedProviderOptions.error,
28	    });
29	  }
30	
31	  return parsedProviderOptions.value;
32	}
