import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { InferSchema } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type { PixelArtModelConfig } from './pixelart-api';
import {
  pixelartFailedResponseHandler,
  pixelartImageResponseSchema,
} from './pixelart-api';
import type { PixelArtImageModelId } from './pixelart-image-settings';

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const {
      prompt,
      n,
      size,
      aspectRatio,
      seed,
      files,
      mask,
      providerOptions,
      headers,
      abortSignal,
    } = options;

    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'This model does not support aspect ratio. Use `size` instead.',
      });
    }

    if (files != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'files',
        details:
          'This model does not support image editing. Only text-to-image generation is supported.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details:
          'This model does not support inpainting. Only text-to-image generation is supported.',
      });
    }

    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
    };

    if (size != null) {
      body.size = size;
    }

    if (seed != null) {
      body.seed = seed;
    }

    if (pixelartOptions?.style != null) {
      body.style = pixelartOptions.style;
    }

    if (pixelartOptions?.pixelDensity != null) {
      body.pixel_density = pixelartOptions.pixelDensity;
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        headers,
      ),
      body,
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelartImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          created: response.created,
        },
      },
    };
  }
}

export const pixelartImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * The visual style for the generated image.
       */
      style: z.enum(['pixel', 'retro', '8bit']).optional(),
      /**
       * The pixel density of the generated image (1-4).
       */
      pixelDensity: z.number().int().min(1).max(4).optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelartImageModelOptionsSchema
>;

